  ApiException({
    required this.message,
    this.statusCode,
    this.responseBody,
  });

  @override
  String toString() =>
      'ApiException(message: $message, statusCode: $statusCode, body: $responseBody)';
}

/// Custom exception for network/connection errors
class NetworkException implements Exception {
  final String message;
  final String? url;

  NetworkException({required this.message, this.url});

  @override
  String toString() => 'NetworkException(message: $message, url: $url)';
}

/// Custom exception for timeout errors
class TimeoutException implements Exception {
